import { Routes, Route } from "react-router-dom";
import Login from "./pages/Login";

function App() {
  return (
    <Routes>
      <Route path="/" element={<Login />} />
      <Route path="/hacker/dashboard" element={<h1>Hacker Dashboard</h1>} />
      <Route path="/company/dashboard" element={<h1>Company Dashboard</h1>} />
      <Route path="/admin/dashboard" element={<h1>Admin Dashboard</h1>} />
    </Routes>
  );
}

export default App;
